def _env_int(name: str, default: int) -> int:
    value = os.getenv(name)
    if value is None:
        return default
    try:
        return int(value)
    except ValueError:
        return default

def _env_keys_from_text(text: str) -> list[str]:
    if not text:
        return []
    match = re.search(r"Environment keys:\s*(.+)", text)
    if not match:
        return []
    return _dedupe([part.strip() for part in match.group(1).split(",")])

def get_repo_root() -> str:
    """Read repo root at runtime to support multi-repo sessions."""
    return os.getenv("RETRIEVAL_REPO_ROOT", REPO_ROOT)

def _load_active_repo_roots() -> set[str]:
    """Return the set of repo_root values from all DB session rows."""
    init_db()
    with db_cursor() as (_conn, cursor):
        rows = cursor.execute("SELECT repo_root FROM repo_sessions").fetchall()
    return {str(row["repo_root"]) for row in rows}

def _fetch_github_repos(access_token: str) -> list[dict]:
    page = 1
    repos: list[dict] = []
    headers = {
        "Authorization": f"Bearer {access_token}",
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28",
    }
    while True:
        response = httpx.get(
            "https://api.github.com/user/repos",
            headers=headers,
            params={
                "per_page": 100,
                "page": page,
                "sort": "updated",
                "visibility": "all",
                "affiliation": "owner,collaborator,organization_member",
            },
            timeout=20.0,
        )
        response.raise_for_status()
        batch = response.json()
        if not isinstance(batch, list) or not batch:
            break
        repos.extend(batch)
        if len(batch) < 100:
            break
        page += 1
    return repos

